('R05','Sedang',5,'Indikator hujan dan durasi sedang.','Bersihkan saluran air.',1),('R06','Sedang',6,'Drainase sedang dan dekat sungai.','Pantau tinggi muka air.',1),('R07','Sedang',7,'Riwayat jarang banjir disertai waspada.','Siapkan perlengkapan darurat.',1),('R08','Sedang',8,'Wilayah sedang dengan curah sedang.','Perkuat mitigasi rumah.',1),('R09','Sedang',9,'Durasi sedang dan drainase sedang.','Lapor jika ada genangan.',1),
